const paymentItems = $input.all();
const historyMap = {};
try {
  for (const h of $('Read Master Sheet').all()) {
    const key = String(h.json['Bill_no.'] || '').trim();
    if (key) historyMap[key] = h.json;
  }
} catch(e) {}
const results = [];
for (const item of paymentItems) {
  const bill = String(item.json['Bill_no.'] || '').trim();
  const h = historyMap[bill] || {};
  results.push({ json: {
    ...item.json,
    First_Reminder_Msg_status:  h.First_Reminder_Msg_status  || '',
    First_Reminder_Date:        h.First_Reminder_Date        || '',
    Second_Reminder_Msg_status: h.Second_Reminder_Msg_status || '',
    Second_Reminder_Date:       h.Second_Reminder_Date       || '',
    Third_Reminder_Msg_status:  h.Third_Reminder_Msg_status  || '',
    Third_Reminder_Date:        h.Third_Reminder_Date        || '',
    Call_Done:                  h.Call_Done                  || '',
    Call_Date:                  h.Call_Date                  || '',
    Customer_Response:          h.Customer_Response          || '',
    Response_Type:              h.Response_Type              || '',
    Followup_Date:              h.Followup_Date              || '',
    Last_Updated:               h.Last_Updated               || ''
  }});
}
return results;

const seen = {};
const uniqueItems = [];
for (const item of $input.all()) {
  const key = String(item.json['Bill_no.'] || '').trim();
  if (!seen[key]) { seen[key] = true; uniqueItems.push(item); }
}
const results = [];
for (const item of uniqueItems) {
  const d = item.json;
  const days = parseInt(d.Days) || 0;
  const balance = parseFloat(d.remaining_balance) || 0;
  const firstStatus  = d.First_Reminder_Msg_status  || '';
  const secondStatus = d.Second_Reminder_Msg_status || '';
  const thirdStatus  = d.Third_Reminder_Msg_status  || '';
  const callDone     = d.Call_Done || '';
  const savedFollowup = d.Followup_Date || '';

  function isFollowupDue(dateStr) {
    if (!dateStr) return true;
    const p = dateStr.split('/');
    if (p.length !== 3) return true;
    const dt = new Date(p[2] + '-' + p[1] + '-' + p[0]);
    dt.setHours(0,0,0,0);
    const today = new Date(); today.setHours(0,0,0,0);
    return today >= dt;
  }
  function addDays(n) {
    const dt = new Date();
    dt.setDate(dt.getDate() + n);
    return String(dt.getDate()).padStart(2,'0') + '/' +
           String(dt.getMonth()+1).padStart(2,'0') + '/' + dt.getFullYear();
  }

  let action = 'SKIP', reason = '', next_followup_date = '';

  if (balance <= 0) {
    action = 'SKIP'; reason = 'Paid';
  } else if (days >= 90 && callDone !== 'Yes') {
    action = 'VOICE_CALL'; reason = days + ' days - voice call needed';
  } else if (days > 60 && days < 90) {
    if (firstStatus !== 'Sent') {
      action = 'WHATSAPP_1'; reason = 'First reminder';
      if (days + 15 < 90)      next_followup_date = addDays(15);
      else if (days + 7 < 90)  next_followup_date = addDays(7);
      else                     next_followup_date = addDays(90 - days);
    } else if (secondStatus !== 'Sent') {
      if (!isFollowupDue(savedFollowup)) {
        action = 'SKIP'; reason = 'Waiting: ' + savedFollowup; next_followup_date = savedFollowup;
      } else {
        action = 'WHATSAPP_2'; reason = 'Second reminder due';
        if (days + 7 < 90) next_followup_date = addDays(7);
        else               next_followup_date = addDays(90 - days);
      }
    } else if (thirdStatus !== 'Sent') {
      if (!isFollowupDue(savedFollowup)) {
        action = 'SKIP'; reason = 'Waiting: ' + savedFollowup; next_followup_date = savedFollowup;
      } else {
        action = 'WHATSAPP_3'; reason = 'Third reminder due';
        next_followup_date = addDays(90 - days);
      }
    } else {
      action = 'SKIP'; reason = 'All reminders sent'; next_followup_date = savedFollowup;
    }
  } else {
    action = 'SKIP'; reason = 'Days ' + days + ' not in range';
  }
  results.push({ json: { ...d, action, action_reason: reason, days_int: days, next_followup_date } });
}
return results;

